async function main() {
  console.log(`🌱 Seeding ${mountains.length} mountains...`);
  let count = 0;
  for (const m of mountains) {
    await prisma.mountain.upsert({
      where: { slug: m.slug },
      update: m,
      create: m,
    });
    count++;
    if (count % 50 === 0) console.log(`  ${count}/${mountains.length}...`);
  }
  console.log(`✅ Done! Seeded ${mountains.length} mountains.`);
}

main()
  .catch((e) => { console.error('Seed failed:', e); process.exit(1); })
  .finally(async () => { await prisma.$disconnect(); });
